_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


//As a base, sample the main sampler at normal vUv coordinates and store as return value:
ret = texture(sampler_main, vUv).xyz;

//Define the translation in (x,y)-direction and multiply by uTexSize.zw to convert the length to pixels:
vec2 shift = vec2(2,2)*uTexSize.zw;

//Take the original vUv coordinates as a starting point, store in second set of coordinates:
vec2 uv2 = vUv;

//Start iterations...
int n = 1;
while (n<=12) {

//First step: put origin in center;
uv2 = uv2-.5;

//Next, rotate by a factor we set in the per-uFrame equations - q32 is cos(angle) and q31 is sin(angle):
uv2 = vec2((uv2.x)*q32 - (uv2.y) * q31,(uv2.x)* q31 + (uv2.y) * q32)+.5;

//Then, shift vUv coordinates n times - see the step after the next as to why:
uv2 += n*shift;

//Sample the main sampler at our new uv2 coordinates,
//deduct the result from the current return value,
//store in ret as absolute (difference) value:
ret = abs(ret-GetPixel(uv2));

//Remove the shift so we won't rotate it with our coordinates in the next iteration:
uv2 -= n*shift;

//Iteration +1
n++;
}


  fragColor = ret;
}
